  path: '/api/upload',
  datastore: new FileStore({ directory: process.env.STORAGE_ROOT! }), // Docker volume, e.g. /data/uploads
  // swap later: new S3Store({ partSize: 8*1024*1024, s3ClientConfig: {...} })
  maxSize: 20 * 1024 * 1024 * 1024, // 20 GB hard cap (or return per-user in hook)
  respectForwardedHeaders: true,

  // ---- per-user QUOTA enforced BEFORE bytes flow ----
  async onUploadCreate(req, upload) {
    const userId = await authUser(req);
    const declared = Number(upload.size ?? 0);            // Upload-Length
    const { used, limit } = await getQuota(userId);
    if (used + declared > limit) {
      throw { status_code: 413, body: 'Storage quota exceeded' };
    }
    return { metadata: { ...upload.metadata, userId } };
  },

  // ---- finalize: reconcile usage, hash, dedup, enqueue thumbs ----
  async onUploadFinish(req, upload) {
    const userId = upload.metadata?.userId!;
    await incrementUsage(userId, upload.size ?? 0);
    // path of the finished blob = join(STORAGE_ROOT, upload.id)
    await enqueue('post-process', { id: upload.id, meta: upload.metadata });
    return {};
  },
});

