// ---------- 3) StorageProvider abstraction ----------
export interface StorageProvider {
  put(key: string, body: Readable, meta?: Record<string,string>): Promise<{ size:number; hash:string }>;
  get(key: string): Promise<Readable>;
  stream(key: string, range?: { start:number; end:number }): Promise<Readable>;
  stat(key: string): Promise<{ size:number } | null>;
  exists(key: string): Promise<boolean>;
  delete(key: string): Promise<void>;
}
// LocalDiskProvider (streaming write + sha256 content-addressing)
import { createWriteStream, createReadStream } from 'node:fs';
import { pipeline } from 'node:stream/promises';
import { createHash } from 'node:crypto';
import { stat, rename, mkdir } from 'node:fs/promises';
import { join, dirname } from 'node:path';
class LocalDiskProvider implements StorageProvider {
  constructor(private root: string) {}
  private p(key:string){ return join(this.root, key); }
  async put(key:string, body:Readable){
    const tmp = this.p(key)+'.part';
    await mkdir(dirname(tmp),{recursive:true});
    const hash = createHash('sha256');
    body.on('data', c => hash.update(c));           // hash while writing
    await pipeline(body, createWriteStream(tmp));
    const digest = hash.digest('hex');
    const finalKey = `blobs/${digest.slice(0,2)}/${digest.slice(2,4)}/${digest}`;
    const dest = this.p(finalKey);
    await mkdir(dirname(dest),{recursive:true});
    await rename(tmp, dest);                          // content-addressed name = dedup + integrity
    const { size } = await stat(dest);
    return { size, hash: digest, key: finalKey } as any;
  }
  async stream(key:string, range?:{start:number;end:number}){
    return createReadStream(this.p(key), range);     // {start,end} -> partial read
  }
  /* get/stat/exists/delete via fs; S3Provider = GetObjectCommand({Range}) + lib-storage Upload */
}

