// app/api/files/[id]/route.ts
export const runtime = 'nodejs';
export async function GET(req: Request, { params }:{params:{id:string}}) {
  const { key, size, contentType } = await lookup(params.id);
  const range = req.headers.get('range');
  if (!range) {
    const body = await storage.stream(key);
    return new Response(Readable.toWeb(body) as any, {
      headers: { 'Content-Length': String(size), 'Content-Type': contentType,
                 'Accept-Ranges': 'bytes' } });
  }
  const m = /bytes=(\d*)-(\d*)/.exec(range)!;
  const start = m[1] ? parseInt(m[1]) : 0;
  const end   = m[2] ? parseInt(m[2]) : size - 1;
  const body = await storage.stream(key, { start, end });
  return new Response(Readable.toWeb(body) as any, {
    status: 206,
    headers: { 'Content-Range': `bytes ${start}-${end}/${size}`,
               'Accept-Ranges': 'bytes',
               'Content-Length': String(end - start + 1),
               'Content-Type': contentType } });
}

