const DownloadCard  = dynamic(() => import('./DownloadCard'));

export function PreviewRouter({ file }) {
  const { mime, ext } = file;
  if (mime.startsWith('image/')) return <ImageLightbox file={file} />;
  if (mime.startsWith('video/')) return <VideoPlayer file={file} />;
  if (mime.startsWith('audio/')) return <AudioPlayer file={file} />;
  if (mime === 'application/pdf') return <PdfViewer file={file} />;
  if (['md','txt','js','ts','py','json','css','html'].includes(ext)) return <CodeViewer file={file} />;
  if (ext === 'docx') return <DocxViewer file={file} />;
  if (['xlsx','xls','csv'].includes(ext)) return <XlsxViewer file={file} />;
  return <DownloadCard file={file} />; // pptx, unknown, binary -> download/iframe
}

