  const size = await getSize(params.id);
  if (!range) {
    return new Response(await getStream(params.id), {
      headers: { 'Content-Length': String(size), 'Accept-Ranges': 'bytes', 'Content-Type': mime },
    });
  }
  const [s, e] = range.replace('bytes=', '').split('-');
  const start = Number(s); const end = e ? Number(e) : size - 1;
  return new Response(await getStream(params.id, start, end), {
