function TiltCard({children}){
  const x=useMotionValue(0), y=useMotionValue(0);
  const rx=useSpring(useTransform(y,[-.5,.5],[8,-8]),{stiffness:300,damping:20});
  const ry=useSpring(useTransform(x,[-.5,.5],[-8,8]),{stiffness:300,damping:20});
  return (
   <motion.div className="glass p-6" style={{rotateX:rx, rotateY:ry, transformPerspective:900}}
     onPointerMove={e=>{const r=e.currentTarget.getBoundingClientRect();
       x.set((e.clientX-r.left)/r.width-.5); y.set((e.clientY-r.top)/r.height-.5);}}
